import { useState, useEffect, useMemo } from "react";
import { Link } from "react-router-dom";
import CourseList from "../components/CourseList";

function Courses() {
  const [courses, setCourses] = useState([]);
  const [newCourse, setNewCourse] = useState("");
  const [loaded, setLoaded] = useState(false);

  useEffect(() => {
    const data = localStorage.getItem("courses");
    if (data) setCourses(JSON.parse(data));
    setLoaded(true);
  }, []);

  useEffect(() => {
    if (loaded) localStorage.setItem("courses", JSON.stringify(courses));
  }, [courses, loaded]);

  function handleAdd() {
    if (newCourse === "") return;
    setCourses([...courses, newCourse]);
    setNewCourse("");
  }

  function handleDelete(index) {
    setCourses(courses.filter((_, i) => i !== index));
  }

  const totalCourse = useMemo(() => courses.length, [courses]);

  return (
    <div style={{ padding: 20 }}>
      <Link to="/">Quay lại</Link>

      <h2>Quản lý khóa học</h2>
      <p>Tổng số khóa học: {totalCourse}</p>

      <input
        value={newCourse}
        onChange={(e) => setNewCourse(e.target.value)}
        placeholder="Tên khóa học"
      />

      <button onClick={handleAdd}>Thêm</button>

      <CourseList courses={courses} onDelete={handleDelete} />
    </div>
  );
}

export default Courses;
